#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5,INF=1e9;

int n,op[N],num[N],a[N],pos[N];
int ls1[N],ls2[N],m1,m2,cnt,c[N][2];
bool del[N];
map<int,int> id1,id2;

int lowbit(int x){
    return x&(-x);
}

void add(int x,int k,int tp){
    if(tp==0){
        for(;x<=m1;x+=lowbit(x))
            c[x][0]+=k;
    }else{
        for(;x<=m2;x+=lowbit(x))
            c[x][1]+=k;
    }
}

int ask(int x,int tp){
    int res=0;
    for(;x;x-=lowbit(x))
        res+=c[x][tp];
    return res;
}

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        char s[8];
        scanf("%s",s);
        if(s[0]=='A'){
            op[i]=0;
            int b,c;
            scanf("%d%d%d",&a[i],&b,&c);
            if(a[i]!=0){
                if(a[i]>0)
                    ls1[++m1]=num[++cnt]=floor(1.0*(c-b)/a[i]);
                else
                    ls2[++m2]=num[++cnt]=INF-ceil(1.0*(c-b)/a[i]);
            }else if(b>c)
                ls1[++m1]=num[++cnt]=-INF;
            else
                ls1[++m1]=num[++cnt]=INF;
            pos[cnt]=i;
        }else if(s[0]=='D'){
            op[i]=1;
            scanf("%d",&a[i]);
        }else{
            op[i]=2;
            scanf("%d",&a[i]);
            ls1[++m1]=a[i];
            ls2[++m2]=INF-a[i];
        }
    }
    sort(ls1+1,ls1+m1+1);
    m1=unique(ls1+1,ls1+m1+1)-ls1-1;
    for(int i=1;i<=m1;i++)
        id1[ls1[i]]=i;
    sort(ls2+1,ls2+m2+1);
    m2=unique(ls2+1,ls2+m2+1)-ls2-1;
    for(int i=1;i<=m2;i++)
        id2[ls2[i]]=i;
    for(int i=1,j=0;i<=n;i++){
        if(op[i]==0){
            j++;
            if(a[i]>=0)
                add(id1[num[j]],1,0);
            else
                add(id2[num[j]],1,1);
            //printf("%d\n",num[j]);
        }else if(op[i]==1){
            if(!del[a[i]]){
                del[a[i]]=1;
                int p=pos[a[i]];
                if(a[p]>=0)
                    add(id1[num[a[i]]],-1,0);
                else
                    add(id2[num[a[i]]],-1,1);
            }
        }else{
            printf("%d\n",ask(id1[a[i]]-1,0)+ask(id2[INF-a[i]]-1,1));
        }
    }
    return 0;
}
